```cpp
    class Iterator {
        const Node* m_current;
    public:
        Iterator(const Node* node) : m_current(node) {}
        const T& operator*() const { return m_current->value; }
        Iterator& operator++() {
            m_current = m_current->next.get();
            return *this;
