class Command {
public:
    virtual ~Command() = default;
    virtual void execute() const = 0;
};

class SetBrightnessCommand : public Command {
    Light& m_light;
    int m_level;
public:
    SetBrightnessCommand(Light& light, int level)
        : m_light(light), m_level(level) {}
    void execute() const override {
        m_light.turnOn();
        m_light.setBrightness(m_level);
    }
};

class MacroCommand : public Command {
    vector<unique_ptr<Command>> m_commands;
public:
    void add(unique_ptr<Command> command) {
        m_commands.push_back(std::move(command));
    }
    void execute() const override {
        for (const auto& c : m_commands) c->execute();
    }
};
