import sys
import json


class Reading:
    def __init__(self, line):
        timestamp, sensor, value = line.strip().split(",")
        self.timestamp = timestamp
        self.sensor = sensor
        self.value = float(value)

    def __lt__(self, other):
        return self.value < other.value

    def __repr__(self):
        return f"Reading({self.sensor}={self.value})"


def read_readings(path):
    with open(path) as f:
        return [Reading(line) for line in f if line.strip()]


def peak_per_sensor(readings):
    sensors = {r.sensor for r in readings}
    return {s: max([r.value for r in readings if r.sensor == s])
            for s in sensors}


def main():
    if len(sys.argv) != 2:
        print("error: usage: sensors.py <log_file>", file=sys.stderr)
        sys.exit(1)
    try:
        readings = read_readings(sys.argv[1])
        peaks = peak_per_sensor(readings)
        with open("peaks.json", "w") as out:
            json.dump(peaks, out)
    except Exception as e:
        print(f"error: {e}", file=sys.stderr)
        sys.exit(1)


if __name__ == "__main__":
    main()
```

הערות: ב-`read_readings` ההבנה `[Reading(line) for line in f ...]` עוברת על אובייקט הקובץ שורה-אחר-שורה (streaming) בלי לטעון את כולו לזיכרון עם `readlines`. ב-`peak_per_sensor` משתמשים ברעיון הדו-שלבי — קבוצת החיישנים הייחודיים ואז `max` על ערכי כל חיישן. ה-`main` מפעפע חריגות פנימיות ותופס אותן לצורך הדפסה נקייה ל-stderr.
